{
  "inputText": "Quarterly sales report for Q3 2025. Revenue grew 23% YoY driven by enterprise expansion. Key wins include Acme Corp ($450K ARR) and GlobalTech ($320K ARR). Churn decreased to 4.2% from 5.8% last quarter.",
  "textMode": "generate",
  "format": "presentation",
  "numCards": 8,
  "themeId": "YOUR_THEME_ID",
  "textOptions": {
    "amount": "medium",
    "tone": "professional, data-driven",
    "audience": "executive leadership team"
  }
}

{
  "inputText": "The Future of Renewable Energy\n---\nSolar power costs have dropped 89% since 2010\n---\nWind energy now provides 10% of global electricity\n---\nBattery storage technology is the missing piece\n---\nPolicy frameworks driving adoption worldwide",
  "textMode": "generate",
  "format": "presentation",
  "cardSplit": "inputTextBreaks",
  "imageOptions": {
    "source": "aiGenerated",
    "model": "flux-kontext-fast",
    "stylePreset": "photorealistic"
  },
  "cardOptions": {
    "dimensions": "16x9"
  },
  "additionalInstructions": "Use bold data visualizations where possible. Make the title card visually striking."
}

{
  "inputText": "Product launch plan for Project Aurora. Target launch date: April 15. Key milestones include beta testing (March 1-15), marketing campaign kickoff (March 20), press embargo lift (April 10), and launch event (April 15).",
  "textMode": "generate",
  "format": "presentation",
  "numCards": 12,
  "cardSplit": "auto",
  "themeId": "YOUR_THEME_ID",
  "textOptions": {
    "amount": "detailed",
    "tone": "professional, inspiring",
    "audience": "cross-functional product team",
    "language": "en"
  },
  "imageOptions": {
    "source": "aiGenerated",
    "stylePreset": "illustration"
  },
  "cardOptions": {
    "dimensions": "16x9",
    "headerFooter": {
      "topRight": {
        "type": "image",
        "source": "themeLogo",
        "size": "sm"
      },
      "bottomLeft": {
        "type": "text",
        "value": "Confidential — Internal Use Only"
      },
      "bottomRight": {
        "type": "cardNumber"
      },
      "hideFromFirstCard": true,
      "hideFromLastCard": true
    }
  },
  "sharingOptions": {
    "workspaceAccess": "view",
    "externalAccess": "noAccess",
    "emailOptions": {
      "recipients": ["pm@example.com", "eng-lead@example.com"],
      "access": "comment"
    }
  },
  "folderIds": ["YOUR_FOLDER_ID"],
  "exportAs": "pdf",
  "additionalInstructions": "Include a timeline visualization card. End with a clear call-to-action slide listing next steps and owners."
}

{
  "inputText": "Write a comprehensive onboarding guide for new engineering hires. Cover: development environment setup, code review process, deployment pipeline, on-call rotation, and team communication norms.",
  "textMode": "generate",
  "format": "document",
  "numCards": 6,
  "textOptions": {
    "amount": "extensive",
    "tone": "friendly, helpful",
    "audience": "new software engineers"
  },
  "imageOptions": {
    "source": "noImages"
  },
  "cardOptions": {
    "dimensions": "pageless"
  }
}

{
  "inputText": "5 tips for better remote meetings: 1. Camera on 2. Mute when not speaking 3. Use the chat for questions 4. Share agenda beforehand 5. End 5 minutes early",
  "textMode": "preserve",
  "format": "social",
  "numCards": 5,
  "imageOptions": {
    "source": "aiGenerated",
    "style": "bold, colorful, graphic design"
  },
  "cardOptions": {
    "dimensions": "4x5"
  },
  "exportAs": "png"
}

{
  "inputText": "Paste your long-form content here — meeting notes, research papers, reports, etc. Gamma will condense it into a concise presentation while preserving key points.",
  "textMode": "condense",
  "format": "presentation",
  "numCards": 8,
  "textOptions": {
    "amount": "brief"
  },
  "imageOptions": {
    "source": "pictographic"
  }
}

{
  "inputText": "# Our New Office\nWe're excited to announce our new headquarters!\n\nhttps://images.unsplash.com/photo-1497366216548-37526070297c?w=1200\n---\n# The Team Space\nCollaborative areas designed for cross-functional work.\n\nhttps://images.unsplash.com/photo-1522071820081-009f0129c71c?w=1200\n---\n# What's Next\nJoin us for the grand opening on April 1st!",
  "textMode": "preserve",
  "format": "presentation",
  "cardSplit": "inputTextBreaks",
  "imageOptions": {
    "source": "noImages"
  },
  "cardOptions": {
    "dimensions": "16x9"
  }
}

{
  "gammaId": "YOUR_TEMPLATE_GAMMA_ID",
  "prompt": "Create a version of this pitch deck for our Series B fundraise. Revenue is $8M ARR, growing 3x YoY, with 200 enterprise customers."
}

{
  "gammaId": "YOUR_TEMPLATE_GAMMA_ID",
  "prompt": "Adapt this client proposal template for Acme Corp. They need a data platform migration from on-prem to cloud. Budget is $2M, timeline is 6 months. Key stakeholders: CTO (technical depth), CFO (ROI focus).",
  "themeId": "YOUR_THEME_ID",
  "imageOptions": {
    "model": "flux-kontext-fast",
    "style": "clean, corporate, modern"
  },
  "sharingOptions": {
    "workspaceAccess": "edit",
    "emailOptions": {
      "recipients": ["sales-lead@example.com"],
      "access": "comment"
    }
  },
  "folderIds": ["YOUR_FOLDER_ID"],
  "exportAs": "pptx"
}
